window.QUESTIONS_D1 = [
{"id":"RW-D1-01","domain":0,"cog":"AP","correct":"B","task":"Task 1.A.4, 1.A.5","stem":"A rural clinic wants to launch video visits for hypertension follow-up. The vendor platform will store visit notes, images, and patient messages. Before signing the contract, what should the clinic do FIRST from a privacy and compliance perspective?","opts":[{"l":"A","c":false,"t":"Ask physicians to use personal video accounts until the vendor is live"},{"l":"B","c":true,"t":"Execute a Business Associate Agreement and review the vendor&#x27;s security controls"},{"l":"C","c":false,"t":"Announce the service on the patient portal"},{"l":"D","c":false,"t":"Build a custom interface to the state HIE"}],"rat":"The vendor will create, receive, maintain, or transmit PHI, so the BAA and security due diligence come before production use."},
{"id":"RW-D1-11","domain":0,"cog":"RE","correct":"B","task":"Task 1.A.1","stem":"A community clinic in a rural county receives enhanced Medicare and Medicaid reimbursement and must serve uninsured patients regardless of ability to pay, funded in part by federal grants. This organization is BEST described as:","opts":[{"l":"A","c":false,"t":"An Accountable Care Organization"},{"l":"B","c":true,"t":"A Federally Qualified Health Center"},{"l":"C","c":false,"t":"A long-term care facility"},{"l":"D","c":false,"t":"An integrated delivery network"}],"rat":"FQHCs receive federal funding through HRSA and must serve underserved populations on a sliding-fee scale regardless of insurance status."},
{"id":"RW-D1-13","domain":0,"cog":"AN","correct":"B","task":"Task 1.A.1","stem":"A regional hospital contractually aligns with independent primary care physicians and a home health agency to jointly manage Medicare patient outcomes and costs — but all parties remain separately owned. This arrangement is MOST consistent with:","opts":[{"l":"A","c":false,"t":"An Integrated Delivery Network"},{"l":"B","c":true,"t":"An Accountable Care Organization"},{"l":"C","c":false,"t":"A Federally Qualified Health Center"},{"l":"D","c":false,"t":"Horizontal integration"}],"rat":"ACOs coordinate care and share accountability across separately owned organizations; IDNs involve common ownership of multiple facility types."},
{"id":"RW-D1-26","domain":0,"cog":"RE","correct":"B","task":"Task 1.A.1","stem":"A patient is seen by their family physician for a routine check-up, then referred to a cardiologist for arrhythmia evaluation, and finally sent to a cardiac surgery program for valve replacement. These three levels of care are respectively described as:","opts":[{"l":"A","c":false,"t":"Acute, post-acute, long-term care"},{"l":"B","c":true,"t":"Primary, specialty, tertiary care"},{"l":"C","c":false,"t":"Ambulatory, inpatient, home health"},{"l":"D","c":false,"t":"Fee-for-service, managed care, capitation"}],"rat":"Primary = first-contact preventive care; Specialty = referred for a specific condition; Tertiary = highly specialized, often referral-only (transplant, complex surgery)."},
{"id":"RW-D1-27","domain":0,"cog":"RE","correct":"B","task":"Task 1.A.1","stem":"A hospital&#x27;s payer mix includes Medicare, Medicaid, and commercial insurance. Which payer is a joint federal-state program that finances healthcare for low-income individuals, including many nursing home residents?","opts":[{"l":"A","c":false,"t":"Medicare"},{"l":"B","c":true,"t":"Medicaid"},{"l":"C","c":false,"t":"CHIP only"},{"l":"D","c":false,"t":"TRICARE"}],"rat":"Medicaid is jointly funded by federal and state governments and covers low-income individuals including those in long-term care; Medicare is the federal program primarily for individuals 65+."},
{"id":"RW-D1-28","domain":0,"cog":"AP","correct":"B","task":"Task 1.A.1, 1.A.5","stem":"A hospital system transitions from billing for each individual service to a contract where it receives a fixed monthly payment per patient to manage their total healthcare needs. This model is BEST described as:","opts":[{"l":"A","c":false,"t":"Fee-for-service"},{"l":"B","c":true,"t":"Capitation / value-based care"},{"l":"C","c":false,"t":"Diagnosis-Related Group payment"},{"l":"D","c":false,"t":"Cost-plus reimbursement"}],"rat":"Capitation pays a fixed per-member-per-month rate for all covered services, shifting financial risk to the provider and incentivizing preventive care — a core feature of value-based models."},
{"id":"RW-D1-02","domain":0,"cog":"AN","correct":"B","task":"Task 1.A.2","stem":"A patient arrives unconscious in the ED after traveling from another state. The local hospital has no prior record. The physician needs medication history and recent discharge information. Which exchange method is MOST appropriate?","opts":[{"l":"A","c":false,"t":"Directed exchange to a known receiving provider"},{"l":"B","c":true,"t":"Query-based HIE lookup across participating organizations"},{"l":"C","c":false,"t":"Consumer-mediated exchange through the patient portal"},{"l":"D","c":false,"t":"Faxed release-of-information request after stabilization"}],"rat":"Query-based exchange is used when the provider does not know where all relevant records are held and needs to search a network."},
{"id":"RW-D1-04","domain":0,"cog":"AN","correct":"B","task":"Task 1.A.2, 1.B.2","stem":"A hospital discharges patients to several skilled nursing facilities. Medication discrepancies are common within 24 hours of transfer. Which intervention BEST addresses the information continuity problem?","opts":[{"l":"A","c":false,"t":"Ask patients to carry printed medication lists"},{"l":"B","c":true,"t":"Send a C-CDA transition-of-care document and standardize medication reconciliation workflow"},{"l":"C","c":false,"t":"Train SNF billing staff on inpatient DRG coding"},{"l":"D","c":false,"t":"Give the SNFs view-only access to the hospital&#x27;s entire EHR"}],"rat":"The problem is a care transition gap, so structured exchange plus reconciliation workflow is the strongest solution."},
{"id":"RW-D1-23","domain":0,"cog":"AP","correct":"B","task":"Task 1.A.2","stem":"A hospital acquires two smaller community hospitals in adjacent markets to expand inpatient capacity. This growth strategy is BEST described as:","opts":[{"l":"A","c":false,"t":"Vertical integration"},{"l":"B","c":true,"t":"Horizontal integration"},{"l":"C","c":false,"t":"Consumer-mediated exchange"},{"l":"D","c":false,"t":"ACO formation"}],"rat":"Horizontal integration combines organizations of the same type (hospital + hospital); vertical integration acquires upstream or downstream organizations (e.g., hospital acquires SNF)."},
{"id":"RW-D1-29","domain":0,"cog":"AP","correct":"C","task":"Task 1.A.2","stem":"A patient uses a smartphone app to aggregate health records from three different providers and shares a curated summary with a new specialist. Which HIE method does this represent?","opts":[{"l":"A","c":false,"t":"Directed exchange"},{"l":"B","c":false,"t":"Query-based exchange"},{"l":"C","c":true,"t":"Consumer-mediated exchange"},{"l":"D","c":false,"t":"Push-based exchange"}],"rat":"Consumer-mediated exchange puts the patient in control of collecting, managing, and sharing their own health data across providers."},
{"id":"RW-D1-30","domain":0,"cog":"AN","correct":"B","task":"Task 1.A.2","stem":"A state-funded HIE serves all payers and providers in a geographic region and receives grants to connect rural hospitals to specialists. A competing health system operates its own internal exchange for its owned facilities only. These are examples of:","opts":[{"l":"A","c":false,"t":"Directed and query-based exchange, respectively"},{"l":"B","c":true,"t":"Public HIE and private HIE, respectively"},{"l":"C","c":false,"t":"Community HIE and consumer-mediated exchange, respectively"},{"l":"D","c":false,"t":"FHIR-based and HL7 v2.x-based exchange, respectively"}],"rat":"Public HIEs are government-funded and serve broad regional populations; private HIEs are operated by a single health system for internal information sharing."},
{"id":"RW-D1-10","domain":0,"cog":"AN","correct":"B","task":"Task 1.A.3, 1.B.1","stem":"A health system acquires two outpatient practices and wants standard workflows, shared patient identity, and shared quality reporting, while keeping some local support staff. Which operating model is MOST consistent with this?","opts":[{"l":"A","c":false,"t":"Completely decentralized IT"},{"l":"B","c":true,"t":"Matrix IT governance with enterprise standards and local support"},{"l":"C","c":false,"t":"No governance until after go-live"},{"l":"D","c":false,"t":"Separate EHR instances with no data sharing"}],"rat":"Matrix governance balances enterprise standardization with local operational support."},
{"id":"RW-D1-16","domain":0,"cog":"AP","correct":"C","task":"Task 1.A.3","stem":"After an EHR go-live, physicians are creating workarounds, skipping order sets, and documenting inconsistently. Adoption is stalling. Which HIT leadership role is BEST positioned to lead the remediation effort?","opts":[{"l":"A","c":false,"t":"CISO"},{"l":"B","c":false,"t":"CIO"},{"l":"C","c":true,"t":"CMIO"},{"l":"D","c":false,"t":"Project Manager"}],"rat":"The CMIO bridges clinical staff and IT and is the physician champion for EHR adoption, workflow optimization, and clinical change management."},
{"id":"RW-D1-31","domain":0,"cog":"AP","correct":"B","task":"Task 1.A.3","stem":"After an EHR implementation, nursing documentation workflows are inefficient and nurses report poor usability of assessment screens. Which HIT role is BEST suited to lead the nursing workflow optimization effort?","opts":[{"l":"A","c":false,"t":"CMIO"},{"l":"B","c":true,"t":"CNIO"},{"l":"C","c":false,"t":"CISO"},{"l":"D","c":false,"t":"Help Desk Tier 2"}],"rat":"The CNIO (Chief Nursing Informatics Officer) is the nursing counterpart to the CMIO, responsible for nursing workflow optimization and nursing input into EHR design."},
{"id":"RW-D1-06","domain":0,"cog":"AN","correct":"B","task":"Task 1.A.4","stem":"A behavioral health clinic treats patients with substance use disorder. The health system wants to include all notes in its enterprise HIE feed. What concern should the HIT leader raise FIRST?","opts":[{"l":"A","c":false,"t":"Whether PACS storage is sufficient"},{"l":"B","c":true,"t":"Whether 42 CFR Part 2 consent and segmentation requirements apply"},{"l":"C","c":false,"t":"Whether the billing system supports CPT modifiers"},{"l":"D","c":false,"t":"Whether the HIE uses a private cloud"}],"rat":"Substance use disorder records carry stricter confidentiality requirements than standard HIPAA; 42 CFR Part 2 requires separate consent and data segmentation."},
{"id":"RW-D1-05","domain":0,"cog":"AP","correct":"B","task":"Task 1.A.4, 1.B.2","stem":"A patient asks a certified EHR hospital to send their data to a third-party app. The hospital has privacy concerns but no specific legal basis to deny the request. What is the BEST response?","opts":[{"l":"A","c":false,"t":"Deny the request because third-party apps are never covered by HIPAA"},{"l":"B","c":true,"t":"Support access through the appropriate standardized API workflow while documenting privacy education"},{"l":"C","c":false,"t":"Require the patient to pick up paper records only"},{"l":"D","c":false,"t":"Charge an interface development fee before releasing any data"}],"rat":"21st Century Cures Act information blocking rules and ONC API requirements favor appropriate access; without a valid exception, denial may constitute information blocking."},
{"id":"RW-D1-08","domain":0,"cog":"AN","correct":"B","task":"Task 1.A.4, 1.B.2","stem":"A vendor says it cannot connect its EHR to a competing scheduling app because &quot;security is too risky,&quot; but cannot identify a specific security control or exception. What should the organization do?","opts":[{"l":"A","c":false,"t":"Accept the explanation and abandon integration"},{"l":"B","c":true,"t":"Evaluate whether an information blocking exception truly applies and document the decision"},{"l":"C","c":false,"t":"Disable all API access for patient safety"},{"l":"D","c":false,"t":"Replace the scheduling app immediately"}],"rat":"Security may be a valid exception, but it must be specific, proportionate, and documented — vague security claims do not qualify automatically."},
{"id":"RW-D1-14","domain":0,"cog":"AP","correct":"C","task":"Task 1.A.4","stem":"A hospital discovers that 620 patient records were accessed by an unauthorized employee over two months. Which HIPAA Breach Notification Rule requirements apply?","opts":[{"l":"A","c":false,"t":"Notify only the affected patients"},{"l":"B","c":false,"t":"Notify HHS and patients, but not media because the number is under 1,000"},{"l":"C","c":true,"t":"Notify the affected patients, HHS, and prominent media in the affected area because the breach exceeds 500 individuals"},{"l":"D","c":false,"t":"Notify only the state attorney general"}],"rat":"Breaches involving 500+ individuals in a jurisdiction require notification to affected individuals, HHS, and prominent local media outlets."},
{"id":"RW-D1-15","domain":0,"cog":"AP","correct":"C","task":"Task 1.A.4","stem":"An uninsured patient arrives in the ED with chest pain. Registration staff request proof of insurance before the on-call physician can see the patient. Which federal law does this process most directly threaten to violate?","opts":[{"l":"A","c":false,"t":"Stark Law"},{"l":"B","c":false,"t":"HIPAA Privacy Rule"},{"l":"C","c":true,"t":"EMTALA"},{"l":"D","c":false,"t":"Anti-Kickback Statute"}],"rat":"EMTALA requires emergency medical screening and stabilization for all individuals presenting at an ED, regardless of insurance status or ability to pay."},
{"id":"RW-D1-17","domain":0,"cog":"AP","correct":"C","task":"Task 1.A.4","stem":"A research team wants to share a patient dataset with a university partner. They remove all 18 PHI identifiers defined by HIPAA before transmission. Which de-identification method are they applying?","opts":[{"l":"A","c":false,"t":"Expert Determination"},{"l":"B","c":false,"t":"Limited Data Set creation"},{"l":"C","c":true,"t":"Safe Harbor de-identification"},{"l":"D","c":false,"t":"Data minimization"}],"rat":"Safe Harbor requires removal of all 18 HIPAA-defined identifiers. Expert Determination uses statistical certification — a different approach requiring a qualified statistician."},
{"id":"RW-D1-21","domain":0,"cog":"AP","correct":"C","task":"Task 1.A.4","stem":"A psychiatric hospital is seeking formal accreditation for its substance use disorder treatment and rehabilitation programs. Which accreditation body is MOST relevant?","opts":[{"l":"A","c":false,"t":"The Joint Commission"},{"l":"B","c":false,"t":"NCQA"},{"l":"C","c":true,"t":"CARF"},{"l":"D","c":false,"t":"DNV GL"}],"rat":"CARF accredits rehabilitation and behavioral health organizations, including substance use disorder treatment programs."},
{"id":"RW-D1-25","domain":0,"cog":"AN","correct":"C","task":"Task 1.A.4","stem":"HITECH was enacted in 2009 to strengthen HIPAA. Which capability did HITECH add that HIPAA did not originally include?","opts":[{"l":"A","c":false,"t":"The requirement for Business Associate Agreements"},{"l":"B","c":false,"t":"The definition of PHI and its 18 identifiers"},{"l":"C","c":true,"t":"Increased monetary penalty tiers and direct applicability of security requirements to business associates"},{"l":"D","c":false,"t":"The EMTALA emergency screening requirement"}],"rat":"HITECH increased maximum civil money penalties, created tiered penalty structures based on culpability, and extended direct HIPAA Security Rule obligations to business associates."},
{"id":"RW-D1-39","domain":0,"cog":"AP","correct":"C","task":"Task 1.A.4","stem":"A physician group refers patients exclusively to a physical therapy practice the physicians co-own and bills those services to Medicare. The federal law MOST directly applicable to this arrangement is:","opts":[{"l":"A","c":false,"t":"EMTALA"},{"l":"B","c":false,"t":"HIPAA Privacy Rule"},{"l":"C","c":true,"t":"Stark Law"},{"l":"D","c":false,"t":"21st Century Cures Act"}],"rat":"The Stark Law prohibits physician self-referral for designated health services billed to Medicare or Medicaid when the physician has a financial relationship with the receiving entity."},
{"id":"RW-D1-09","domain":0,"cog":"AP","correct":"A","task":"Task 1.A.5, 1.B.1","stem":"A population health team wants to identify diabetic patients who missed annual retinal exams and target outreach. Which application category is MOST relevant?","opts":[{"l":"A","c":true,"t":"Business intelligence and population health analytics"},{"l":"B","c":false,"t":"PACS"},{"l":"C","c":false,"t":"RIS"},{"l":"D","c":false,"t":"Pharmacy dispensing system"}],"rat":"This task requires aggregating clinical data, identifying care gaps, and generating targeted outreach — all functions of BI and population health platforms."},
{"id":"RW-D1-12","domain":0,"cog":"AP","correct":"B","task":"Task 1.A.5","stem":"A health system redesigns EHR workflows specifically to reduce after-hours documentation burden on physicians and prevent clinician burnout. Which aim framework does this initiative directly address beyond the original Triple Aim?","opts":[{"l":"A","c":false,"t":"The IHI Sepsis Bundle"},{"l":"B","c":true,"t":"The Quadruple Aim"},{"l":"C","c":false,"t":"Meaningful Use Stage 3"},{"l":"D","c":false,"t":"The SDOH framework"}],"rat":"The Quadruple Aim adds clinician well-being and work experience to the Triple Aim&#x27;s three dimensions (patient experience, population health, per-capita cost)."},
{"id":"RW-D1-22","domain":0,"cog":"AN","correct":"C","task":"Task 1.A.5","stem":"An oncology center uses a patient&#x27;s tumor genomic profile to select chemotherapy drugs most likely to be effective for that individual rather than following a standard population-based protocol. This approach is BEST described as:","opts":[{"l":"A","c":false,"t":"Remote patient monitoring"},{"l":"B","c":false,"t":"Population health risk stratification"},{"l":"C","c":true,"t":"Precision medicine"},{"l":"D","c":false,"t":"Natural language processing"}],"rat":"Precision medicine uses individual genetic, molecular, or biomarker data to customize treatment rather than applying one-size-fits-all population-based protocols."},
{"id":"RW-D1-40","domain":0,"cog":"AP","correct":"C","task":"Task 1.A.5","stem":"A health system deploys connected weight scales and blood pressure cuffs for 500 heart failure patients to transmit daily readings to a care team dashboard. Which technology trend does this MOST directly represent?","opts":[{"l":"A","c":false,"t":"Precision medicine"},{"l":"B","c":false,"t":"mHealth patient portals"},{"l":"C","c":true,"t":"Remote patient monitoring via wearable/IoMT devices"},{"l":"D","c":false,"t":"Consumer-mediated HIE"}],"rat":"IoMT (Internet of Medical Things) devices continuously collect patient data outside the clinical setting; RPM uses this data stream to enable proactive care intervention."},
{"id":"RW-D1-03","domain":0,"cog":"AP","correct":"A","task":"Task 1.B.1","stem":"A five-hospital system has frequent duplicate patient records when patients receive care at different campuses. Which technology should be prioritized?","opts":[{"l":"A","c":true,"t":"Enterprise Master Patient Index"},{"l":"B","c":false,"t":"Patient portal replacement"},{"l":"C","c":false,"t":"New charge description master"},{"l":"D","c":false,"t":"Radiology PACS upgrade"}],"rat":"An EMPI provides patient identity matching across multiple facilities and systems using probabilistic or deterministic algorithms."},
{"id":"RW-D1-36","domain":0,"cog":"AP","correct":"B","task":"Task 1.B.1","stem":"A patient is admitted to a hospital, transferred from the ICU to a medical floor, and then discharged to a rehabilitation center. Which clinical application is the PRIMARY source of record for tracking these movements in real time?","opts":[{"l":"A","c":false,"t":"EHR clinical documentation module"},{"l":"B","c":true,"t":"ADT (Admission, Discharge, Transfer) system"},{"l":"C","c":false,"t":"Revenue cycle management system"},{"l":"D","c":false,"t":"PACS"}],"rat":"The ADT system is the authoritative source for patient registration, location, and movement events; it also triggers HL7 ADT messages to downstream systems."},
{"id":"RW-D1-37","domain":0,"cog":"AP","correct":"C","task":"Task 1.B.1","stem":"A patient manages their own health record by collecting data from multiple providers and sharing a customized summary with each new care team. This tool is patient-owned and not tethered to any single provider. It is BEST described as:","opts":[{"l":"A","c":false,"t":"EHR"},{"l":"B","c":false,"t":"EMR"},{"l":"C","c":true,"t":"PHR (Personal Health Record)"},{"l":"D","c":false,"t":"CCD"}],"rat":"A PHR is patient-controlled and not tied to a specific provider system, unlike an EHR (provider-managed, shareable) or EMR (provider-managed, not designed for sharing)."},
{"id":"RW-D1-07","domain":0,"cog":"AP","correct":"B","task":"Task 1.B.2","stem":"Nurses report that BCMA scanning fails in two medication rooms, but only during peak evening rounds. Which infrastructure issue should be investigated FIRST?","opts":[{"l":"A","c":false,"t":"Charge capture logic"},{"l":"B","c":true,"t":"Wireless network coverage and capacity"},{"l":"C","c":false,"t":"DRG grouper configuration"},{"l":"D","c":false,"t":"Patient portal authentication"}],"rat":"Mobile bedside workflows depend on reliable wireless connectivity; time-of-day failures during high concurrency point to capacity or coverage gaps."},
{"id":"RW-D1-18","domain":0,"cog":"AN","correct":"B","task":"Task 1.B.2","stem":"An integration team must connect a new third-party patient engagement app to the EHR. The vendor offers both HL7 v2.x and FHIR options. Which is the stronger choice for this use case and why?","opts":[{"l":"A","c":false,"t":"HL7 v2.x, because it is the most widely deployed legacy standard"},{"l":"B","c":true,"t":"FHIR, because it uses RESTful APIs and JSON better suited to modern web and mobile app development"},{"l":"C","c":false,"t":"HL7 v2.x, because FHIR cannot carry lab result data"},{"l":"D","c":false,"t":"Either is equally appropriate for third-party app integration"}],"rat":"FHIR&#x27;s RESTful, resource-based design and JSON support make it the preferred choice for modern apps; HL7 v2.x is pipe-delimited and designed for internal system-to-system messaging."},
{"id":"RW-D1-19","domain":0,"cog":"AP","correct":"C","task":"Task 1.B.2","stem":"A hospital contracts with an EHR company to access clinical software hosted entirely by the vendor — the vendor manages hardware, operating system, and application updates. The hospital pays a monthly subscription. This delivery model is:","opts":[{"l":"A","c":false,"t":"IaaS"},{"l":"B","c":false,"t":"PaaS"},{"l":"C","c":true,"t":"SaaS"},{"l":"D","c":false,"t":"Private cloud"}],"rat":"SaaS delivers a fully hosted and managed application over the internet; the organization consumes the software without managing any underlying infrastructure."},
{"id":"RW-D1-20","domain":0,"cog":"AP","correct":"B","task":"Task 1.B.2","stem":"An outpatient network&#x27;s scheduling system must send appointment data to three clinical applications, each using a different message format. Rather than building three separate interfaces, the IT team deploys a central component that translates and routes messages. This component is called:","opts":[{"l":"A","c":false,"t":"A data warehouse"},{"l":"B","c":true,"t":"An interface engine"},{"l":"C","c":false,"t":"A VPN concentrator"},{"l":"D","c":false,"t":"A clinical data repository"}],"rat":"An interface engine (middleware) translates messages between formats and routes them to the correct destination, reducing point-to-point integration complexity."},
{"id":"RW-D1-24","domain":0,"cog":"AP","correct":"C","task":"Task 1.B.2","stem":"A security operations team wants to aggregate log data from all servers, network devices, and clinical applications into a single platform that correlates events and sends real-time alerts when suspicious patterns are detected. Which technology supports this?","opts":[{"l":"A","c":false,"t":"VPN"},{"l":"B","c":false,"t":"IDS only"},{"l":"C","c":true,"t":"SIEM (Security Information and Event Management)"},{"l":"D","c":false,"t":"Interface engine"}],"rat":"SIEM centralizes log collection, performs event correlation, and generates alerts for security monitoring and incident response across the enterprise."},
{"id":"RW-D1-33","domain":0,"cog":"AP","correct":"B","task":"Task 1.B.2","stem":"A hospital&#x27;s radiology department needs to transmit CT scan images from the scanner to a radiologist workstation in a remote building for interpretation. The MOST appropriate standard for this transmission is:","opts":[{"l":"A","c":false,"t":"HL7 FHIR"},{"l":"B","c":true,"t":"DICOM"},{"l":"C","c":false,"t":"HL7 v2.x ADT message"},{"l":"D","c":false,"t":"C-CDA document"}],"rat":"DICOM (Digital Imaging and Communications in Medicine) is the universal standard for storing, transmitting, and displaying medical images."},
{"id":"RW-D1-34","domain":0,"cog":"AP","correct":"B","task":"Task 1.B.2","stem":"A health system is moving clinical applications to the cloud and wants to prevent unauthorized access even if credentials are stolen. Which combination of security controls BEST addresses this risk?","opts":[{"l":"A","c":false,"t":"Firewall and VPN only"},{"l":"B","c":true,"t":"SSO and MFA (Single Sign-On combined with Multi-Factor Authentication)"},{"l":"C","c":false,"t":"VLAN segmentation and audit logs"},{"l":"D","c":false,"t":"Encryption at rest and IDS"}],"rat":"SSO reduces password fatigue and enables centralized access control; MFA requires a second verification factor, protecting against credential theft."},
{"id":"RW-D1-35","domain":0,"cog":"AP","correct":"C","task":"Task 1.B.2","stem":"An organization hosts its public-facing patient portal on a server segment that is separated from the internal clinical network by two firewalls — one facing the internet and one facing the internal systems. This architecture is called:","opts":[{"l":"A","c":false,"t":"VLAN"},{"l":"B","c":false,"t":"VPN"},{"l":"C","c":true,"t":"DMZ (Demilitarized Zone)"},{"l":"D","c":false,"t":"CDR"}],"rat":"A DMZ is a network segment that isolates public-facing servers from both the internet and internal systems, reducing the blast radius if the public server is compromised."},
{"id":"RW-D1-38","domain":0,"cog":"RE","correct":"B","task":"Task 1.B.2","stem":"The Integrating the Healthcare Enterprise (IHE) initiative publishes:","opts":[{"l":"A","c":false,"t":"Federal regulations governing EHR certification"},{"l":"B","c":true,"t":"Implementation frameworks (profiles) that specify how existing standards like HL7 and DICOM should be used for specific clinical workflows"},{"l":"C","c":false,"t":"Proprietary messaging formats competing with HL7 FHIR"},{"l":"D","c":false,"t":"Accreditation standards for health IT departments"}],"rat":"IHE profiles do not create new standards — they specify how to use existing standards (HL7, DICOM) for defined interoperability use cases such as document sharing (XDS) and patient identity (PIX/PDQ)."},
{"id":"RW-D1-41","domain":0,"cog":"RE","correct":"B","task":"Task 1.A.1","stem":"A 78-year-old patient with dementia needs 24-hour nursing supervision, wound care, and physical therapy after a hip fracture but cannot return home independently. The MOST appropriate care setting is:","opts":[{"l":"A","c":false,"t":"Acute care hospital for continued inpatient treatment"},{"l":"B","c":true,"t":"Skilled nursing facility (SNF)"},{"l":"C","c":false,"t":"Ambulatory surgery center"},{"l":"D","c":false,"t":"FQHC"}],"rat":"SNFs / long-term care facilities provide extended nursing, rehabilitation, and custodial care for patients requiring 24-hour supervision but not acute hospital-level care."},
{"id":"RW-D1-42","domain":0,"cog":"AP","correct":"B","task":"Task 1.A.1","stem":"A patient enrolled in an HMO requires a referral from their primary care physician before seeing a cardiologist. A patient in a PPO can see the cardiologist directly but pays higher out-of-pocket costs. Which statement BEST describes the key operational difference?","opts":[{"l":"A","c":false,"t":"HMOs reimburse providers on a fee-for-service basis; PPOs use capitation"},{"l":"B","c":true,"t":"HMOs require coordination through a gatekeeper PCP; PPOs allow direct specialist access at higher member cost"},{"l":"C","c":false,"t":"PPOs always provide lower total cost than HMOs"},{"l":"D","c":false,"t":"HMOs only cover inpatient services"}],"rat":"HMOs require a PCP gatekeeper referral and have lower premiums; PPOs allow self-referrals to specialists but charge more for out-of-network or direct access — a key managed care distinction."},
{"id":"RW-D1-43","domain":0,"cog":"RE","correct":"C","task":"Task 1.A.1","stem":"A hospital affiliated with a medical school provides complex tertiary care, conducts federally funded clinical trials, and trains medical residents and nursing students. This organization is BEST described as:","opts":[{"l":"A","c":false,"t":"A Federally Qualified Health Center"},{"l":"B","c":false,"t":"A community health center"},{"l":"C","c":true,"t":"An Academic Medical Center (AMC)"},{"l":"D","c":false,"t":"A long-term care facility"}],"rat":"AMCs combine research, education (GME/nursing training), and clinical care — often serving as tertiary/quaternary referral centers with specialized programs not available elsewhere."},
{"id":"RW-D1-44","domain":0,"cog":"AP","correct":"B","task":"Task 1.A.1, 1.A.4","stem":"A primary care practice redesigns its care model to emphasize team-based care, coordinated chronic disease management, enhanced patient access, and quality improvement. It seeks formal recognition from NCQA. This model is BEST described as:","opts":[{"l":"A","c":false,"t":"Integrated Delivery Network"},{"l":"B","c":true,"t":"Patient-Centered Medical Home (PCMH)"},{"l":"C","c":false,"t":"Accountable Care Organization"},{"l":"D","c":false,"t":"Health Maintenance Organization"}],"rat":"The PCMH model (recognized by NCQA) emphasizes coordinated, accessible, team-based primary care with a focus on whole-person care and chronic disease management — distinct from ACOs (which focus on cost/quality shared savings across a broader network)."},
{"id":"RW-D1-45","domain":0,"cog":"AP","correct":"C","task":"Task 1.A.2","stem":"A hospital ED physician needs to send a patient&#x27;s discharge summary and medication list securely to a specific known primary care physician at another organization for post-discharge follow-up. Which HIE method is MOST appropriate?","opts":[{"l":"A","c":false,"t":"Query-based exchange"},{"l":"B","c":false,"t":"Consumer-mediated exchange"},{"l":"C","c":true,"t":"Directed exchange"},{"l":"D","c":false,"t":"Broadcast exchange"}],"rat":"Directed exchange is a secure, point-to-point transmission from one known provider to another — similar to secure email. It is used when the receiving provider is already known, unlike query-based exchange which searches for unknown records."},
{"id":"RW-D1-46","domain":0,"cog":"AN","correct":"C","task":"Task 1.A.2","stem":"A hospital system acquires a skilled nursing facility, a home health agency, and an outpatient physical therapy practice — expanding its services both upstream and downstream from acute care. This strategy is BEST described as:","opts":[{"l":"A","c":false,"t":"Horizontal integration"},{"l":"B","c":false,"t":"ACO formation"},{"l":"C","c":true,"t":"Vertical integration"},{"l":"D","c":false,"t":"Consumer-mediated exchange"}],"rat":"Vertical integration acquires organizations at different points along the care continuum (clinic → acute hospital → SNF → home health). Horizontal integration merges same-type organizations (e.g., hospital + hospital)."},
{"id":"RW-D1-47","domain":0,"cog":"AP","correct":"C","task":"Task 1.A.2","stem":"A care management nurse coordinates daily communication among a diabetic patient&#x27;s endocrinologist, cardiologist, and primary care physician to align treatment plans and prevent conflicting medications. This activity is BEST described as:","opts":[{"l":"A","c":false,"t":"Care transition management"},{"l":"B","c":false,"t":"Utilization management"},{"l":"C","c":true,"t":"Care coordination"},{"l":"D","c":false,"t":"Disease registry management"}],"rat":"Care coordination is the deliberate organization of patient care activities across providers and settings to ensure appropriate, safe, and effective care. Care transitions refer specifically to a patient&#x27;s movement between care settings."},
{"id":"RW-D1-48","domain":0,"cog":"RE","correct":"C","task":"Task 1.A.2, 1.B.2","stem":"The structured clinical document format used to exchange patient information at care transitions — including medications, allergies, problems, and visit notes — in a standardized, machine-readable format is called:","opts":[{"l":"A","c":false,"t":"HL7 v2.x ADT message"},{"l":"B","c":false,"t":"DICOM header"},{"l":"C","c":true,"t":"C-CDA (Consolidated Clinical Document Architecture)"},{"l":"D","c":false,"t":"FHIR Questionnaire resource"}],"rat":"C-CDA is the ONC-required structured document standard for care transition exchange (Transition of Care / Referral Note). It replaced the earlier CCD as the dominant format for Meaningful Use / Promoting Interoperability."},
{"id":"RW-D1-49","domain":0,"cog":"AP","correct":"C","task":"Task 1.A.3","stem":"A health system&#x27;s senior IT executive develops the 3-year technology roadmap, oversees the $12M annual IT capital budget, and aligns IT investments with the board-approved organizational strategic plan. Which HIT leadership role does this describe?","opts":[{"l":"A","c":false,"t":"CMIO"},{"l":"B","c":false,"t":"CISO"},{"l":"C","c":true,"t":"CIO"},{"l":"D","c":false,"t":"HIT Project Manager"}],"rat":"The CIO (Chief Information Officer) is responsible for enterprise IT strategy, governance, capital budget, and alignment of IT investments with organizational goals — the top IT leadership role."},
{"id":"RW-D1-50","domain":0,"cog":"AP","correct":"C","task":"Task 1.A.3","stem":"A health system has both a CISO and a Privacy Officer. A ransomware attack encrypts clinical records; separately, a patient files a complaint about unauthorized disclosure of their psychiatric records. Which roles lead each response?","opts":[{"l":"A","c":false,"t":"Privacy Officer leads both"},{"l":"B","c":false,"t":"CISO leads both"},{"l":"C","c":true,"t":"CISO leads the ransomware technical response; Privacy Officer leads the unauthorized disclosure investigation"},{"l":"D","c":false,"t":"The Compliance Officer leads both"}],"rat":"CISO = security incidents, ePHI technical controls, cybersecurity response. Privacy Officer = HIPAA Privacy Rule compliance, PHI disclosure policies, and patient complaint investigations. Both roles often collaborate but have distinct primary responsibilities."},
{"id":"RW-D1-51","domain":0,"cog":"RE","correct":"B","task":"Task 1.A.3","stem":"A nurse calls the help desk because she cannot log into the EHR. The Tier 1 agent performs basic troubleshooting and cannot resolve the issue, then escalates it to a Tier 2 technical analyst. This process is an example of:","opts":[{"l":"A","c":false,"t":"An emergency change management process"},{"l":"B","c":true,"t":"A tiered help desk support model"},{"l":"C","c":false,"t":"A Change Advisory Board review"},{"l":"D","c":false,"t":"A benefits realization escalation"}],"rat":"Tiered help desk support routes issues from Tier 1 (basic troubleshooting, password resets) to Tier 2 (technical analysts) to Tier 3 (vendor or engineering escalation) based on complexity and resolution capability."},
{"id":"RW-D1-52","domain":0,"cog":"AN","correct":"C","task":"Task 1.A.3","stem":"A hospital system centralizes all IT staff, infrastructure, and decision-making at corporate headquarters. Each facility has no local IT staff and submits all requests to the central team. This structure maximizes standardization but raises concerns about local responsiveness. This is BEST described as:","opts":[{"l":"A","c":false,"t":"Matrix IT governance"},{"l":"B","c":false,"t":"Decentralized IT governance"},{"l":"C","c":true,"t":"Centralized IT governance"},{"l":"D","c":false,"t":"Federated IT governance"}],"rat":"Centralized IT maximizes standardization and cost efficiency but may reduce local responsiveness. Decentralized IT maximizes local control but loses standardization. Matrix governance balances both with enterprise standards and local support."},
{"id":"RW-D1-53","domain":0,"cog":"AN","correct":"C","task":"Task 1.A.4","stem":"A pharmaceutical company pays a hospital&#x27;s pharmacy director a consulting fee; in return, the director ensures the hospital formulary favors that company&#x27;s drugs over clinically equivalent alternatives. No physician referral is involved. Which law MOST directly applies?","opts":[{"l":"A","c":false,"t":"Stark Law"},{"l":"B","c":false,"t":"EMTALA"},{"l":"C","c":true,"t":"Anti-Kickback Statute"},{"l":"D","c":false,"t":"HIPAA Privacy Rule"}],"rat":"The Anti-Kickback Statute (AKS) prohibits any remuneration to induce or reward referrals or purchases of items/services under federal healthcare programs — broader than Stark Law, which covers physician self-referral specifically."},
{"id":"RW-D1-54","domain":0,"cog":"AP","correct":"C","task":"Task 1.A.4","stem":"A hospital&#x27;s research team wants to share a patient dataset but retains some identifiers that would be removed under Safe Harbor. A qualified statistician reviews the data and certifies that the probability of re-identifying any individual is very small. Which de-identification method is being used?","opts":[{"l":"A","c":false,"t":"Safe Harbor"},{"l":"B","c":false,"t":"Limited Data Set"},{"l":"C","c":true,"t":"Expert Determination"},{"l":"D","c":false,"t":"Data minimization"}],"rat":"Expert Determination uses a qualified statistician to certify that re-identification risk is very small — an alternative to Safe Harbor that may allow more data utility while still meeting HIPAA de-identification standards."},
{"id":"RW-D1-55","domain":0,"cog":"AP","correct":"B","task":"Task 1.A.4","stem":"A nurse accesses a patient&#x27;s electronic record out of curiosity to see if the patient is her neighbor&#x27;s ex-spouse — she is not involved in the patient&#x27;s care. Under HIPAA, which principle does this most directly violate?","opts":[{"l":"A","c":false,"t":"Breach notification standard"},{"l":"B","c":true,"t":"Minimum necessary standard"},{"l":"C","c":false,"t":"Business Associate Agreement requirement"},{"l":"D","c":false,"t":"42 CFR Part 2 restriction"}],"rat":"HIPAA&#x27;s minimum necessary standard requires PHI to be accessed only to the extent necessary to accomplish the intended purpose. Accessing records without a care-related purpose violates this principle."},
{"id":"RW-D1-56","domain":0,"cog":"RE","correct":"D","task":"Task 1.A.4","stem":"Under HIPAA&#x27;s Safe Harbor de-identification method, which of the following geographic data elements is NOT included in the 18 PHI identifiers that must be removed?","opts":[{"l":"A","c":false,"t":"Patient&#x27;s ZIP code (in low-population areas)"},{"l":"B","c":false,"t":"Patient&#x27;s city of residence"},{"l":"C","c":false,"t":"Patient&#x27;s county of residence"},{"l":"D","c":true,"t":"Patient&#x27;s state of residence"}],"rat":"State of residence is NOT one of HIPAA&#x27;s 18 PHI identifiers. Geographic data smaller than state (such as ZIP codes where the population is ≤20,000) ARE identifiers, but the state itself is not."},
{"id":"RW-D1-57","domain":0,"cog":"AP","correct":"C","task":"Task 1.A.4","stem":"A hospital uses one cloud vendor to store fully de-identified research data and another cloud vendor to process individually identifiable patient billing records on the hospital&#x27;s behalf. Which arrangement requires a Business Associate Agreement?","opts":[{"l":"A","c":false,"t":"The de-identified research data processing only"},{"l":"B","c":false,"t":"Both arrangements equally"},{"l":"C","c":true,"t":"The billing records processing — the vendor creates, receives, or maintains PHI on the hospital&#x27;s behalf"},{"l":"D","c":false,"t":"Neither arrangement, since cloud storage is not clinical"}],"rat":"A BAA is required when a vendor creates, receives, maintains, or transmits PHI on behalf of a covered entity. Truly de-identified data is not PHI and does not trigger the BAA requirement."},
{"id":"RW-D1-58","domain":0,"cog":"AP","correct":"B","task":"Task 1.A.4","stem":"A primary care group practice wants accreditation that recognizes quality of care, care coordination, and patient experience in an outpatient physician practice setting. Which accreditation body is MOST relevant?","opts":[{"l":"A","c":false,"t":"The Joint Commission (TJC)"},{"l":"B","c":true,"t":"NCQA"},{"l":"C","c":false,"t":"CARF"},{"l":"D","c":false,"t":"DNV GL"}],"rat":"NCQA accredits health plans and physician practices (including the PCMH model). TJC primarily accredits hospitals and health systems; CARF covers rehabilitation and behavioral health."},
{"id":"RW-D1-59","domain":0,"cog":"AN","correct":"B","task":"Task 1.A.5","stem":"A community health center adds housing stability screening, food insecurity assessment, and transportation access questions to its intake process. Data is used to connect patients with social services and adjust care plans. This initiative integrates:","opts":[{"l":"A","c":false,"t":"Precision medicine genomic data into care planning"},{"l":"B","c":true,"t":"Social Determinants of Health (SDOH) into population health management"},{"l":"C","c":false,"t":"Remote patient monitoring devices for chronic disease"},{"l":"D","c":false,"t":"Consumer-mediated HIE for data aggregation"}],"rat":"SDOH (social determinants of health) are non-clinical factors — housing, food, transportation, income, education — that significantly impact health outcomes. Integrating SDOH data into care planning is a key population health management strategy."},
{"id":"RW-D1-60","domain":0,"cog":"RE","correct":"B","task":"Task 1.A.5","stem":"The Triple Aim framework developed by the Institute for Healthcare Improvement (IHI) includes which three dimensions?","opts":[{"l":"A","c":false,"t":"Patient safety, cost reduction, and staff satisfaction"},{"l":"B","c":true,"t":"Improving patient experience, improving population health, and reducing per-capita cost"},{"l":"C","c":false,"t":"Patient satisfaction, clinician satisfaction, and operational efficiency"},{"l":"D","c":false,"t":"Quality, safety, and access"}],"rat":"The IHI Triple Aim targets: (1) improving individual patient care experience and satisfaction, (2) improving the health of populations, and (3) reducing the per-capita cost of healthcare."},
{"id":"RW-D1-61","domain":0,"cog":"AP","correct":"B","task":"Task 1.A.5","stem":"A patient with uncontrolled hypertension receives a smartphone app that sends daily blood pressure reading reminders, tracks medication adherence, and alerts the care team when readings exceed a threshold. This application category is BEST described as:","opts":[{"l":"A","c":false,"t":"PACS system"},{"l":"B","c":true,"t":"mHealth (mobile health) application"},{"l":"C","c":false,"t":"Personal Health Record (PHR)"},{"l":"D","c":false,"t":"Laboratory Information System"}],"rat":"mHealth apps deliver health services and information through mobile devices — including medication reminders, symptom tracking, chronic disease self-management tools, and remote monitoring integrations."},
{"id":"RW-D1-62","domain":0,"cog":"AN","correct":"B","task":"Task 1.A.5","stem":"An AI algorithm trained on 500,000 chest X-rays flags potential pneumonia findings for radiologist review before the radiologist reads the image, reducing time to diagnosis and catching subtle findings. This technology trend MOST directly represents:","opts":[{"l":"A","c":false,"t":"Blockchain for medical image integrity verification"},{"l":"B","c":true,"t":"AI / machine learning applied to diagnostic imaging"},{"l":"C","c":false,"t":"Remote patient monitoring for vital sign tracking"},{"l":"D","c":false,"t":"Precision medicine for treatment personalization"}],"rat":"AI/ML in medical imaging uses deep learning to identify patterns in images at scale — assisting (not replacing) radiologists by improving diagnostic speed and sensitivity for subtle findings."},
{"id":"RW-D1-63","domain":0,"cog":"AP","correct":"B","task":"Task 1.B.1","stem":"Before CPOE implementation, physicians handwrote medication orders that pharmacists often found illegible or ambiguous, leading to clarification delays and potential dosing errors. Which patient safety benefit is MOST directly realized after CPOE adoption?","opts":[{"l":"A","c":false,"t":"Physicians can now order medications without nursing involvement"},{"l":"B","c":true,"t":"Elimination of handwriting-related errors with embedded dose range checking at the point of order entry"},{"l":"C","c":false,"t":"Pharmacy staff can now modify physician orders without approval"},{"l":"D","c":false,"t":"Medications are dispensed automatically without pharmacist review"}],"rat":"CPOE eliminates handwriting illegibility errors and embeds real-time CDS (dose range checking, drug-allergy alerts, drug-drug interaction alerts) directly at the point of order entry — a core patient safety benefit."},
{"id":"RW-D1-64","domain":0,"cog":"RE","correct":"C","task":"Task 1.B.1","stem":"A clinical application manages the complete laboratory workflow: physician places an order, it tracks specimen collection, receipt, and processing, and delivers finalized results back to the ordering provider in the EHR. This application is called:","opts":[{"l":"A","c":false,"t":"PACS"},{"l":"B","c":false,"t":"RIS (Radiology Information System)"},{"l":"C","c":true,"t":"LIS (Laboratory Information System)"},{"l":"D","c":false,"t":"eMAR"}],"rat":"The LIS manages end-to-end laboratory workflow: order receipt, specimen tracking, result processing, and result delivery. PACS stores medical images; RIS manages radiology scheduling and workflow."},
{"id":"RW-D1-65","domain":0,"cog":"AP","correct":"C","task":"Task 1.B.1","stem":"A hospital&#x27;s revenue cycle team uses a comprehensive master list of every billable item — procedures, supplies, medications, and services — each with associated charge codes and prices. This foundational revenue cycle tool is called:","opts":[{"l":"A","c":false,"t":"EMPI"},{"l":"B","c":false,"t":"MPI"},{"l":"C","c":true,"t":"Charge Description Master (CDM)"},{"l":"D","c":false,"t":"DRG grouper"}],"rat":"The CDM is the hospital&#x27;s complete list of all billable items and their charge codes — the foundation of the charge capture and billing process. It must be maintained accurately to ensure correct claim submission."},
{"id":"RW-D1-66","domain":0,"cog":"AP","correct":"B","task":"Task 1.B.2","stem":"A health system&#x27;s IT team must connect its main campus network to a remote clinic 50 miles away. Which network type describes this long-distance connectivity?","opts":[{"l":"A","c":false,"t":"LAN (Local Area Network)"},{"l":"B","c":true,"t":"WAN (Wide Area Network)"},{"l":"C","c":false,"t":"VLAN"},{"l":"D","c":false,"t":"DMZ"}],"rat":"WANs connect geographically separated networks over long distances. LANs operate within a single building or campus; VLANs are logical segmentation within a network; DMZ is a security architecture zone."},
{"id":"RW-D1-67","domain":0,"cog":"AP","correct":"C","task":"Task 1.B.2","stem":"A health system wants to deploy virtual machines and cloud storage, maintaining full control over the operating system, middleware, and application stack — but without managing physical hardware. Which cloud service model fits this requirement?","opts":[{"l":"A","c":false,"t":"SaaS — the vendor manages everything including the application"},{"l":"B","c":false,"t":"PaaS — the vendor manages the runtime environment and OS"},{"l":"C","c":true,"t":"IaaS (Infrastructure as a Service)"},{"l":"D","c":false,"t":"Hybrid cloud"}],"rat":"IaaS provides virtualized compute, storage, and networking. The organization manages OS and above; the provider manages physical hardware. PaaS adds a managed runtime; SaaS delivers a fully managed application."},
{"id":"RW-D1-68","domain":0,"cog":"AP","correct":"C","task":"Task 1.B.2","stem":"A hospital&#x27;s remote physicians need to access the EHR from home over the public internet. The IT team must ensure all data transmitted between home offices and the hospital is encrypted end-to-end. Which technology achieves this?","opts":[{"l":"A","c":false,"t":"VLAN segmentation"},{"l":"B","c":false,"t":"DMZ architecture"},{"l":"C","c":true,"t":"VPN (Virtual Private Network)"},{"l":"D","c":false,"t":"LAN extension"}],"rat":"A VPN creates an encrypted tunnel over the public internet, protecting data transmitted between a remote endpoint and the hospital network from interception or eavesdropping."},
{"id":"RW-D1-69","domain":0,"cog":"AN","correct":"C","task":"Task 1.B.2","stem":"A hospital&#x27;s data warehouse is populated nightly from the EHR, lab system, and financial system. The process extracts data from source systems, converts it into a standardized format, and loads it into the warehouse. This batch pipeline is called:","opts":[{"l":"A","c":false,"t":"FHIR API integration"},{"l":"B","c":false,"t":"HL7 directed exchange"},{"l":"C","c":true,"t":"ETL (Extract, Transform, Load)"},{"l":"D","c":false,"t":"SIEM data ingestion"}],"rat":"ETL is the batch data pipeline for populating data warehouses — extracting from sources, transforming/normalizing data, and loading into the target repository. API/FHIR enables real-time exchange; ETL handles scheduled batch loads."},
{"id":"RW-D1-70","domain":0,"cog":"AP","correct":"B","task":"Task 1.B.2","stem":"A hospital&#x27;s security policy requires that patient data stored on laptops be protected so that if a device is lost or stolen, the data cannot be read by unauthorized parties. Which security control BEST addresses this requirement?","opts":[{"l":"A","c":false,"t":"MFA on the hospital&#x27;s EHR login screen"},{"l":"B","c":true,"t":"Encryption at rest on the laptop&#x27;s hard drive"},{"l":"C","c":false,"t":"TLS encryption in transit during network communication"},{"l":"D","c":false,"t":"SIEM monitoring of access log events"}],"rat":"Encryption at rest protects data stored on physical media (laptop drives, USB devices, backup tapes) from unauthorized access if the device is physically stolen. Encryption in transit protects data during network transmission — a separate, complementary control."}
];
